handleAddEditEmployeeSubmit = (id, action) => {

    this.setState({screen: 0});

    let headers = new Headers();

    headers.append('Content-Type', 'application/json');
    headers.append('Accept', 'application/json');


    var employeeRequest = {firstname: this.state.firstname, lastname: this.state.lastname, email: this.state.email, employeeid: this.state.employeeid, startdate: Moment(this.state.startdate).format("MM/DD/YYYY"), enddate: Moment(this.state.enddate).format("MM/DD/YYYY"), studenttype: this.state.studenttype}

    var backUrl = properties.backend + `scheduler/update_employee`


    if (action == "insert") {
       employeeRequest.operation = "insert" 
    }

    if (action == "update") {
        employeeRequest.id = id
        employeeRequest.operation = "update"
    }

    if (action == "delete") {
        employeeRequest.id = id
        employeeRequest.operation = "delete"
    }


    fetch(backUrl, {
      "method": "POST",
      headers: headers,
      body: JSON.stringify(employeeRequest)

    })
    .then(response => response.json())
    .then(response => {
        this.setState({employeeResult: response.employee})
        this.setState({teamResult: response.team})
        this.setState({empScheduleResult: response.employeeSchedule})
        this.setState({permission: response.permission})
        this.setState({screen: 1})
        this.handleCancelAddEditEmployee()
    })
    .catch(err => {
      console.log(err);
    });
}




updateParameter = (event, variableName) => {
  this.setState({[variableName]: event.target.value})
}


updateParameterDate = (date, variableName) => {
  this.setState({[variableName]: date})
}


updateParameterSelect = (selectValue, variableName) => {
    var setJson = {}
    setJson[variableName] = selectValue.value
    this.setState(setJson)
  }


    componentDidMount() {
        this.setState({setCalendarDate: Moment().format("YYYY-MM-DD")})

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `scheduler/update_employee`

        fetch(backUrl, {
          "method": "POST",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({employeeResult: response.employee})
            this.setState({teamResult: response.team})
            this.setState({empScheduleResult: response.employeeSchedule})
            this.setState({permission: response.permission})
            this.setState({screen: 1})
            this.handleCancelAddEditEmployee()
        })
        .catch(err => {
          console.log(err);
        });

    }

    tdStyle = (content) => {
        return <td nowrap="true" style={this.tdStyleCSS()}>{content}</td>
    }


    tdStyleCSS = () => {
        return {border: "1px solid black", padding: "6px"}
    }


    handleDateClick = (arg) => {
        this.setState({dateStr: arg.dateStr})
        this.setState({setCalendarDate: arg.dateStr})
        this.setState({showDate: true})
    }



    handleDidMount = () => {


    }


    handleEventClick = (arg) => {
        this.setState({dateStr: arg.event.startStr})
        this.setState({setCalendarDate: arg.event.startStr})
        this.setState({showDate: true})
    }


    goBackFirstScreen = () => {
        this.setState({showDate: false});
      }



      goForward = () => {
          this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")})
          this.setState({setCalendarDate: Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")})
          this.setState({showDate: true})
      }

      goBack = () => {
          this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")})
          this.setState({setCalendarDate: Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")})
          this.setState({showDate: true})

      }




    render() {


        var header = "Loading ..."
        var content = []
        var rightContent = []
        var leftContent = []




        if (this.state.screen === 1 && (this.state.addEmployee || this.state.editEmployee) && this.state.permission) {
            var tempContent = []

            if (this.state.addEmployee) {
                tempContent.push(<div style={{fontSize: '18px'}}>Add Employee<hr></hr></div>)
            }

            if (this.state.editEmployee) {
                tempContent.push(<div>Edit Employee<hr></hr></div>)
            }

            //firstname = "", lastname = "", email = "", employeeid = "", startdate = "", enddate = "", studenttype = ""

            const studentOptions = [
                {label: 'NP', value: 'NP'},
                {label: 'Dental', value: 'Dental'},
                {label: 'Med', value: 'Med'}
              ]



            var addPanel = <table>
                <tr>
                    <td>First Name: </td>
                    <td style={{width: '300px'}}><input type="text" style={{width: '300px'}} onChange={event => this.updateParameter(event, 'firstname')} value={this.state.firstname}></input></td>
                </tr>
                <tr>
                    <td>Last Name: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'lastname')} value={this.state.lastname}></input></td>
                </tr>
                <tr>
                    <td>Email: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'email')} value={this.state.email}></input></td>
                </tr>
                <tr>
                    <td>Employee ID: </td>
                    <td><input type="text" style={{width: '300px'}}  onChange={event => this.updateParameter(event, 'employeeid')} value={this.state.employeeid}></input></td>
                </tr>
                <tr>
                    <td>Start Date: </td>
                    <td><DatePicker 
                        value={this.state.startdate}
                        onChange={dateArray => {const d = new Date(dateArray);this.updateParameterDate(d, 'startdate')}}
                        plugins={[<DatePanel />]}
                        single
                        format="MM/DD/YYYY"
                    /></td>
                </tr>
                <tr>
                    <td>End Date: </td>
                    <td>
                        <DatePicker 
                        value={this.state.enddate}
                        onChange={dateArray => {const d = new Date(dateArray);this.updateParameterDate(d, 'enddate')}}
                        plugins={[<DatePanel />]}
                        single
                        format="MM/DD/YYYY"
                        />
                    </td>
                </tr>
                <tr>
                    <td>Student Type: </td>
                    <td>
                        <Select
                        value={{label: this.state.studenttype, value: this.state.studenttype}}
                        name="studenttype"
                        options={studentOptions}
                        className="basic-multi-select"
                        classNamePrefix="select"
                        onChange={event => this.updateParameterSelect(event, 'studenttype')}
                        />
                    </td>
                </tr>
            </table>


              tempContent.push(addPanel)





            if (this.state.addEmployee) {
                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelAddEditEmployee()}  id="cancelEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleAddEditEmployeeSubmit("", "insert")}  id="addEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)

            }

            if (this.state.editEmployee) {
                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelAddEditEmployee()}  id="cancelEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleAddEditEmployeeSubmit(this.state.emp_id, "update")}  id="addEmployee" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)

            }


            rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
        }


        if (this.state.screen === 1 && this.state.permission) {


            var employeeResult = this.state.employeeResult

            //for (var index in roomResults) {

            var resultTable = [] 

            if (employeeResult.length > 0) {
                resultTable.push(<tr>{this.tdStyle("First Name")}{this.tdStyle("Last Name")}{this.tdStyle("Email")}{this.tdStyle("Employee ID")}{this.tdStyle("Start Date")}{this.tdStyle("End Date")}{this.tdStyle("Student Type")}{this.tdStyle("")}{this.tdStyle("")}</tr>)

                employeeResult.map(empResult => {
                    resultTable.push(<tr>{this.tdStyle(empResult.first_name)}{this.tdStyle(empResult.last_name)}{this.tdStyle(empResult.email)}{this.tdStyle(empResult.employee_id)}{this.tdStyle(empResult.start_date)}{this.tdStyle(empResult.end_date)}{this.tdStyle(empResult.student_type)}<td style={this.tdStyleCSS()}><button onClick={() => this.handleEditEmployee(empResult)}  id={"editEmployee_" + empResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Edit</button></td><td style={this.tdStyleCSS()}><button onClick={() => this.handleDeleteEmployee(empResult)}  id={"deleteEmployee_" + empResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Delete</button></td></tr>)
                })


                leftContent.push(<div style={{display: "flex"}}><table style={{border: "1px solid black"}}>{resultTable}</table></div>)


            } else {

                leftContent.push(<div style={{display: "flex", width: "400px"}}>Currently there has no employee in the database.</div>)

            }


            var tabContent = []

            var yourSpace = []

            var events = []


            this.state.empScheduleResult.map(rec => {
                events.push({id: "", groupId: "",title: rec.team_name.replace("M-L Wards Team", "") + ": " + rec.first_name + " " + rec.last_name + " - " + rec.student_type,  date: rec.date_value, color: "#FFFFFF", textColor: "black" })
            })



            var employeeChoice = []
            var teamChoice = []
            this.state.teamResult.map(rec => {
                teamChoice.push({label: rec.team_name, value: rec.id})
            })
            this.state.employeeResult.map(rec => {
                employeeChoice.push({label: rec.first_name + ' ' + rec.last_name, value: rec.id})
            })

            var employeeDD =   <Select 
                                name="employeeDD"
                                options={employeeChoice}
                                style={{width: '200px'}}
                                onChange={event => this.updateParameterSelect(event, 'employeeDD')}
                            />

            var teamDD =   <Select 
                            name="teamDD"
                            options={teamChoice}
                            style={{width: '200px'}}
                            onChange={event => this.updateParameterSelect(event, 'teamDD')}
                        />

            var styleLabel = {paddingLeft: "10px", paddingRight: "10px", borderStyle: "solid", border: "1px"}
            var styleSelect = {width: "200px"}



            if (!this.state.showDate) {

                var quickAdd =  <div>&nbsp;&nbsp;<b>- quick add</b><hr></hr><table><tr><td style={styleLabel} valign="top">Team:</td>
                <td style={styleSelect} valign="top">{teamDD}</td>
                <td style={styleLabel} valign="top">Date:</td>
                <td rowSpan={2}> 
                <Calendar 
              value={this.state.selectedDate}
              onChange={dateArray => {this.handleDateChange(dateArray)}}
              multiple={true}
              format="YYYY-MM-DD"
              numberOfMonths={1}

            />
                </td>
                <td style={styleLabel} valign="top">
                    <button style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "yellow"}} onClick={() => this.handleAddEmployeeToDays()}>Add</button>
                    </td></tr>
                    <tr><td style={styleLabel} valign="top">Employee:</td><td style={styleSelect} valign="top">{employeeDD}</td></tr>

                    </table><hr></hr></div>


                yourSpace.push(quickAdd)



                yourSpace.push(                 <FullCalendar
                    plugins={[ dayGridPlugin, interactionPlugin ]}
                    initialView="dayGridMonth"
                    events={events}
                    eventClick={this.handleEventClick}
                    dateClick={this.handleDateClick}
                    eventOrder="id"
                    eventDidMount={this.handleDidMount}
                    initialDate= {this.state.setCalendarDate}
                    //navLinkDayClick={this.handleLinkClick}
                />)
            } else {







                var dropDownAddBox =  <table><tr><td style={styleLabel}>Team:</td><td style={styleSelect}>{teamDD}</td><td style={styleLabel}>Employee:</td><td style={styleSelect}>{employeeDD}</td>
                <td style={styleLabel}><button style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "yellow"}} onClick={() => this.handleAddEmployeeToCalender()}>Add</button></td></tr></table>

                yourSpace.push(<div style={{display: "flex", gap: "15px"}}><button onClick={() => this.goBackFirstScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button>
                <div style={{paddingTop: "3px", fontSize: "20px"}}>{this.state.dateStr}</div><button onClick={() => this.goBack()} style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "green"}}>&lt;</button>
                <button onClick={() => this.goForward()} style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "green"}}>&gt;</button>
                </div>)
                yourSpace.push(<div style={{display: "flex", gap: "100px", marginTop: "20px"}}><div>{dropDownAddBox}</div></div>)
                yourSpace.push(<div><hr></hr></div>)



                var empScheduleResult = this.state.empScheduleResult.filter(rec => rec.date_value == this.state.dateStr)


                var resultTable = [] 

                if (empScheduleResult.length > 0) {
                    resultTable.push(<tr>{this.tdStyle("Team")}{this.tdStyle("First Name")}{this.tdStyle("Last Name")}{this.tdStyle("Email")}{this.tdStyle("Employee ID")}{this.tdStyle("Student Type")}{this.tdStyle("")}</tr>)

                    empScheduleResult.map(empResult => {
                        resultTable.push(<tr>{this.tdStyle(empResult.team_name)}{this.tdStyle(empResult.first_name)}{this.tdStyle(empResult.last_name)}{this.tdStyle(empResult.email)}{this.tdStyle(empResult.employee_id)}{this.tdStyle(empResult.student_type)}<td style={this.tdStyleCSS()}><button onClick={() => this.handleDeleteEmployeeCalendar(empResult)}  id={"deleteEmployeeSchedule_" + empResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Delete</button></td></tr>)
                    })


                    yourSpace.push(<div style={{display: "flex"}}><table style={{border: "1px solid black"}}>{resultTable}</table></div>)


                } else {

                    yourSpace.push(<div style={{display: "flex", width: "400px", marginTop: "30px"}}>Currently there has no employee schedule.</div>)

                }




            }   



            tabContent.push(<Tabs selectedIndex={this.state.tabIndex} onSelect={tabIndex => this.setState({ tabIndex })}>
                <TabList>
                    <Tab>Manage Employee</Tab>
                    <Tab>Manage Schedule</Tab>
                </TabList>
                <TabPanel>
                    <h2>Manage Employee</h2>
                    <h2><button onClick={() => this.handleAddEmployee()}  id="addRoom" style={{height: "30px", width: "150px", fontSize: "16px", backgroundColor: "yellow" }}> + Add Employee</button></h2>
                    <div></div>
                    <div style={{display: "flex"}}><div style={{marginRight: "50px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>
                </TabPanel>
                <TabPanel>
                    <h2>Manage Schedule</h2>
                    <div>{yourSpace}</div>
                </TabPanel>
            </Tabs>)

            content.push(tabContent)


                header = ""

        }



        if (this.state.screen === 1 && !this.state.permission) {

            content.push(<div>You don't have permission for this application! Please contact Keith Siu - keith.siu@ucsf.edu</div>)

            header = ""
        }







        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }





}


export default EmployeeAdmin
